// BTTooltipPaginationStep — PaginationStep / pagination-step balloon molecule.
//
// Public API:
//   - BTTooltipPaginationStep widget
//   - BTTooltipPaginationStepVariant enum
//   - Re-exports BTTooltipPosition and BTTooltipArrowPosition from atoms.
export 'package:btech_ui/src/components/molecules/tooltip_pagination_step/tooltip_pagination_step.types.dart';
export 'package:btech_ui/src/components/molecules/tooltip_pagination_step/tooltip_pagination_step.widget.dart';

// BTTooltipPaginationStep — type definitions.
//
// Figma: node 478-2463 (Pagination Step variants).
// https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=478-2463

export '../tooltip/tooltip.types.dart'
    show BTTooltipArrowPosition, BTTooltipPosition;

/// Navigation button style shown in the step footer.
enum BTTooltipPaginationStepVariant {
  /// Secondary rounded buttons (Prev / Next). Default.
  button,

  /// Text-link buttons — grey Prev, blue Next.
  link,

  /// Icon-only chevron buttons flanking the step label. Centred.
  centered,
}

// ignore_for_file: lines_longer_than_80_chars

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import '../button-link/button_link.widget.dart';
import '../tooltip/internal/tooltip.arrow.dart';
import 'package:btech_ui/src/components/molecules/tooltip_pagination_step/tooltip_pagination_step.types.dart';
import 'package:flutter/material.dart';

/// BTTooltipPaginationStep — PaginationStep / pagination-step balloon.
///
/// Figma: node 2157-1726 (Playground — full PaginationStep instance).
/// https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=478-2463
///
/// A standalone tooltip card used for onboarding coach marks. Positioning
/// relative to the target element is the responsibility of the parent —
/// wrap this in a [Positioned] inside a [Stack].
///
/// ```dart
/// // Base button variant
/// BTTooltipPaginationStep(
///   label: 'Fitur Baru',
///   description: 'Klik tombol ini untuk memulai.',
///   stepLabel: 'Step 1 of 3',
///   stepVariant: BTTooltipPaginationStepVariant.button,
///   hasClose: true,
///   prevLabel: 'Kembali',
///   nextLabel: 'Selanjutnya',
///   position: BTTooltipPosition.bottom,
///   onPrev: _goPrev,
///   onNext: _goNext,
///   onClose: _endTour,
/// )
///
/// // Centered icon-button variant
/// BTTooltipPaginationStep(
///   description: 'Geser untuk navigasi.',
///   stepLabel: 'Step 2 of 5',
///   stepVariant: BTTooltipPaginationStepVariant.centered,
///   position: BTTooltipPosition.top,
///   onPrev: _goPrev,
///   onNext: _goNext,
/// )
/// ```
class BTTooltipPaginationStep extends StatelessWidget {
  const BTTooltipPaginationStep({
    required this.description,
    this.label,
    this.stepLabel,
    this.stepVariant = BTTooltipPaginationStepVariant.button,
    this.hasClose = false,
    this.prevLabel = 'Prev',
    this.nextLabel = 'Next',
    this.position = BTTooltipPosition.top,
    this.arrowPosition = BTTooltipArrowPosition.mid,
    this.arrowOffset,
    this.child,
    this.onPrev,
    this.onNext,
    this.onClose,
    super.key,
  });

  /// Bold title shown at the top of the card. Hidden when null.
  final String? label;

  /// Main description text. Required.
  final String description;

  /// Step indicator, e.g. "Step 1 of 5". Hidden when null.
  final String? stepLabel;

  /// Navigation button style. @default [BTTooltipPaginationStepVariant.button].
  final BTTooltipPaginationStepVariant stepVariant;

  /// Show a × close button in the top-right corner.
  final bool hasClose;

  /// Prev button label. @default 'Prev'.
  final String prevLabel;

  /// Next button label. @default 'Next'.
  final String nextLabel;

  /// Which side the arrow caret renders on. @default [BTTooltipPosition.top].
  final BTTooltipPosition position;

  /// Arrow offset along the axis (enum-based, 5 positions).
  final BTTooltipArrowPosition arrowPosition;

  /// Optional pixel-accurate arrow offset from the balloon's near edge to the
  /// trigger centre. When provided, overrides [arrowPosition] for top/bottom
  /// arrows (horizontal axis). Units: logical pixels.
  ///
  /// • top/bottom balloons → px from balloon **left** edge to trigger centre X.
  /// • left/right balloons → not used (falls back to [arrowPosition]).
  final double? arrowOffset;

  /// Optional rich content rendered between description and footer.
  final Widget? child;

  final VoidCallback? onPrev;
  final VoidCallback? onNext;
  final VoidCallback? onClose;

  // ── Colors (component-specific hardcoded — no btech_tokens equivalent) ───
  // bg.secondary and brand.primary are foundation tokens accessed via context;
  // button text.primary is also a foundation token.
  // Per CLAUDE.md §2: use context.btColor.* for foundation tokens.

  // ── Build ─────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final r = context.btRadius;
    final bg = c.bg.inverse;

    final isVertical = position == BTTooltipPosition.top ||
        position == BTTooltipPosition.bottom;

    final arrow = BTTooltipArrow(direction: position, color: bg);
    final body = _buildBody(context, c, r, bg);

    if (isVertical) {
      // Use pixel-accurate Stack positioning when arrowOffset is supplied,
      // otherwise fall back to the enum-based Align approach.
      final alignedArrow = arrowOffset != null
          ? _buildHorizontalArrowStack(arrow, arrowOffset!)
          : Align(
              alignment: _horizontalArrowAlignment(arrowPosition),
              child: Padding(
                padding: EdgeInsets.symmetric(horizontal: 16.0),
                child: arrow,
              ),
            );
      return Material(
        type: MaterialType.transparency,
        child: SizedBox(
          width: 320.0,
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: position == BTTooltipPosition.bottom
                ? [alignedArrow, body]
                : [body, alignedArrow],
          ),
        ),
      );
    } else {
      final alignedArrow = Align(
        alignment: _verticalArrowAlignment(arrowPosition),
        child: Padding(
          padding: EdgeInsets.symmetric(vertical: 8.0),
          child: arrow,
        ),
      );
      return Material(
        type: MaterialType.transparency,
        child: IntrinsicHeight(
          child: Row(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: position == BTTooltipPosition.left
                ? [body, alignedArrow]
                : [alignedArrow, body],
          ),
        ),
      );
    }
  }

  Widget _buildBody(
    BuildContext context,
    BTColorTheme c,
    BTRadiusTheme r,
    Color bg,
  ) {
    final hasHeader = label != null || hasClose;
    final hasFooter = stepLabel != null;

    return Container(
      width: 320.0,
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(r.sm),
      ),
      padding: EdgeInsets.all(16.0),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // ── Header ──────────────────────────────────────────────────────
          if (hasHeader) ...[
            Row(
              crossAxisAlignment: CrossAxisAlignment.center,
              children: [
                if (label != null)
                  Expanded(
                    child: Text(
                      label!,
                      style: TextStyle(
                        fontFamily: BTTypography.fontFamily,
                        fontSize: 16.0,
                        fontWeight: FontWeight.w700,
                        height: 20 / 16,
                        color: c.text.inverse,
                      ),
                    ),
                  )
                else
                  const Spacer(),
                if (hasClose)
                  GestureDetector(
                    onTap: onClose,
                    child: Icon(Icons.close, color: c.text.inverse, size: 24),
                  ),
              ],
            ),
            SizedBox(height: 8.0),
          ],

          // ── Description ──────────────────────────────────────────────────
          Text(
            description,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 14.0,
              fontWeight: FontWeight.w500,
              height: 16 / 14,
              color: c.text.inverse,
            ),
          ),

          // ── Rich content slot ────────────────────────────────────────────
          if (child != null) ...[
            SizedBox(height: 8.0),
            child!,
          ],

          // ── Footer ───────────────────────────────────────────────────────
          if (hasFooter) ...[
            SizedBox(height: 8.0),
            _buildFooter(context, c, r),
          ],
        ],
      ),
    );
  }

  Widget _buildFooter(
    BuildContext context,
    BTColorTheme c,
    BTRadiusTheme r,
  ) {
    switch (stepVariant) {
      // ── Button variant ─────────────────────────────────────────────────
      case BTTooltipPaginationStepVariant.button:
        return Row(
          children: [
            if (stepLabel != null)
              Expanded(
                child: Text(
                  stepLabel!,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14.0,
                    fontWeight: FontWeight.w500,
                    height: 16 / 14,
                    color: c.text.inverse,
                  ),
                ),
              ),
            BTButton(
              label: prevLabel,
              variant: BTButtonVariant.secondaryLight,
              size: BTButtonSize.sm,
              onPressed: onPrev,
            ),
            SizedBox(width: 8.0),
            BTButton(
              label: nextLabel,
              variant: BTButtonVariant.secondaryLight,
              size: BTButtonSize.sm,
              onPressed: onNext,
            ),
          ],
        );

      // ── Link variant ───────────────────────────────────────────────────
      case BTTooltipPaginationStepVariant.link:
        return Row(
          children: [
            if (stepLabel != null)
              Expanded(
                child: Text(
                  stepLabel!,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14.0,
                    fontWeight: FontWeight.w500,
                    height: 16 / 14,
                    color: c.text.inverse,
                  ),
                ),
              ),
            BTButtonLink.secondary(
              label: prevLabel,
              onPressed: onPrev,
            ),
            SizedBox(width: 12.0),
            BTButtonLink(
              label: nextLabel,
              onPressed: onNext,
            ),
          ],
        );

      // ── Centered icon-button variant ───────────────────────────────────
      case BTTooltipPaginationStepVariant.centered:
        return Row(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Semantics(
              label: 'Sebelumnya',
              button: true,
              child: BTButton.iconOnly(
                icon: const Icon(Icons.chevron_left, color: Colors.white, size: 16),
                variant: BTButtonVariant.primary,
                size: BTButtonSize.sm,
                onPressed: onPrev,
              ),
            ),
            if (stepLabel != null) ...[
              SizedBox(width: 12.0),
              Text(
                stepLabel!,
                style: TextStyle(
                  fontFamily: BTTypography.fontFamily,
                  fontSize: 14.0,
                  fontWeight: FontWeight.w500,
                  height: 16 / 14,
                  color: c.text.inverse,
                ),
              ),
              SizedBox(width: 12.0),
            ],
            Semantics(
              label: 'Selanjutnya',
              button: true,
              child: BTButton.iconOnly(
                icon: const Icon(Icons.chevron_right, color: Colors.white, size: 16),
                variant: BTButtonVariant.primary,
                size: BTButtonSize.sm,
                onPressed: onNext,
              ),
            ),
          ],
        );
    }
  }

  /// Position the arrow SVG (16 × 8 px) using a Stack so its centre lands
  /// at exactly [offset] logical pixels from the balloon's left edge.
  Widget _buildHorizontalArrowStack(Widget arrow, double offset) {
    // Arrow SVG is 16 px wide — subtract 8 to get the left edge position.
    // Clamp so the arrow never escapes the 320 px balloon.
    final left = (offset - 8.0).clamp(0.0, 304.0); // 320 - 16 = 304
    return SizedBox(
      width: 320.0,
      height: 8.0,
      child: Stack(
        clipBehavior: Clip.none,
        children: [Positioned(left: left, top: 0, child: arrow)],
      ),
    );
  }

  Alignment _horizontalArrowAlignment(BTTooltipArrowPosition ap) {
    return switch (ap) {
      BTTooltipArrowPosition.left => Alignment.centerLeft,
      BTTooltipArrowPosition.leftMid => const Alignment(-0.5, 0),
      BTTooltipArrowPosition.mid => Alignment.center,
      BTTooltipArrowPosition.rightMid => const Alignment(0.5, 0),
      BTTooltipArrowPosition.right => Alignment.centerRight,
    };
  }

  Alignment _verticalArrowAlignment(BTTooltipArrowPosition ap) {
    return switch (ap) {
      BTTooltipArrowPosition.left => Alignment.topCenter,
      BTTooltipArrowPosition.leftMid => const Alignment(0, -0.5),
      BTTooltipArrowPosition.mid => Alignment.center,
      BTTooltipArrowPosition.rightMid => const Alignment(0, 0.5),
      BTTooltipArrowPosition.right => Alignment.bottomCenter,
    };
  }
}
